		public static bool MoveNPC(int x, int y, int n)
		{
			if (!StartRoomCheck(x, y))
			{
				Main.NewText(Lang.inter[40], byte.MaxValue, 240, 20);
				return false;
			}
			if (!RoomNeeds(spawnNPC))
			{
				if (Lang.lang <= 1)
				{
					int num = 0;
					string[] array = new string[4];
					if (!roomTorch)
					{
						array[num] = "a light source";
						num++;
					}
					if (!roomDoor)
					{
						array[num] = "a door";
						num++;
					}
					if (!roomTable)
					{
						array[num] = "a table";
						num++;
					}
					if (!roomChair)
					{
						array[num] = "a chair";
						num++;
					}
					string text = "";
					for (int i = 0; i < num; i++)
					{
						if (num == 2 && i == 1)
						{
							text += " and ";
						}
						else if (i > 0 && i != num - 1)
						{
							text += ", and ";
						}
						else if (i > 0)
						{
							text += ", ";
						}
						text += array[i];
					}
					Main.NewText("This housing is missing " + text + ".", byte.MaxValue, 240, 20);
				}
				else
				{
					Main.NewText(Lang.inter[39], byte.MaxValue, 240, 20);
				}
				return false;
			}
			ScoreRoom();
			if (hiScore <= 0)
			{
				if (roomOccupied)
				{
					Main.NewText(Lang.inter[41], byte.MaxValue, 240, 20);
				}
				else if (roomEvil)
				{
					Main.NewText(Lang.inter[42], byte.MaxValue, 240, 20);
				}
				else
				{
					Main.NewText(Lang.inter[40], byte.MaxValue, 240, 20);
				}
				return false;
			}
			if (n > 0 && !CheckConditions(Main.npc[n].type))
			{
				Main.NewText(Lang.inter[55] + " " + Main.npc[n].name, byte.MaxValue, 240, 20);
				return false;
			}
			return true;
		}

		public static void moveRoom(int x, int y, int n)
		{
			if (Main.netMode == 1)
			{
				NetMessage.SendData(60, -1, -1, "", n, x, y, 1f);
				return;
			}
			spawnNPC = Main.npc[n].type;
			Main.npc[n].homeless = true;
			SpawnNPC(x, y);
		}

		public static void kickOut(int n)
		{
			if (Main.netMode == 1)
			{
				NetMessage.SendData(60, -1, -1, "", n);
			}
			else
			{
				Main.npc[n].homeless = true;
			}
		}

		public static bool NextNPC()
		{
			if (CheckConditions(spawnNPC))
			{
				bool flag = false;
				for (int i = 0; i < 200; i++)
				{
					if (Main.npc[i].type == spawnNPC)
					{
						flag = true;
					}
				}
				if (flag)
				{
					return true;
				}
			}
			for (int j = 0; j < 378; j++)
			{
				if (!Main.nextNPC[j] || !CheckConditions(j))
				{
					continue;
				}
				bool flag2 = false;
				for (int k = 0; k < 200; k++)
				{
					if (Main.npc[k].type == j)
					{
						flag2 = true;
					}
				}
				if (flag2)
				{
					Main.nextNPC[j] = false;
					continue;
				}
				spawnNPC = j;
				return true;
			}
			return false;
		}

		public static bool CheckConditions(int type)
		{
			if (type == 160)
			{
				if ((double)roomY2 > Main.worldSurface)
				{
					return false;
				}
				int num = 0;
				int num2 = roomX1 - Main.zoneX / 2 / 16 - 1 - Lighting.offScreenTiles;
				int num3 = roomX2 + Main.zoneX / 2 / 16 + 1 + Lighting.offScreenTiles;
				int num4 = roomY1 - Main.zoneY / 2 / 16 - 1 - Lighting.offScreenTiles;
				int num5 = roomY2 + Main.zoneY / 2 / 16 + 1 + Lighting.offScreenTiles;
				if (num2 < 0)
				{
					num2 = 0;
				}
				if (num3 >= Main.maxTilesX)
				{
					num3 = Main.maxTilesX - 1;
				}
				if (num4 < 0)
				{
					num4 = 0;
				}
				if (num5 > Main.maxTilesX)
				{
					num5 = Main.maxTilesX;
				}
				for (int i = num2 + 1; i < num3; i++)
				{
					for (int j = num4 + 2; j < num5 + 2; j++)
					{
						if (Main.tile[i, j].active() && (Main.tile[i, j].type == 70 || Main.tile[i, j].type == 71 || Main.tile[i, j].type == 72))
						{
							num++;
						}
					}
				}
				if (num >= 100)
				{
					return true;
				}
				return false;
			}
			return true;
		}

		public static void UnspawnTravelNPC()
		{
			int num = -1;
			for (int i = 0; i < 200; i++)
			{
				if (Main.npc[i].active && Main.npc[i].type == 368)
				{
					num = i;
					break;
				}
			}
			if (num < 0)
			{
				return;
			}
			int num2 = (int)(Main.npc[num].center().X / 16f);
			int num3 = (int)(Main.npc[num].center().Y / 16f);
			bool flag = true;
			Rectangle value = new Rectangle(num2 * 16 + 8 - NPC.sWidth / 2 - NPC.safeRangeX, num3 * 16 + 8 - NPC.sHeight / 2 - NPC.safeRangeY, NPC.sWidth + NPC.safeRangeX * 2, NPC.sHeight + NPC.safeRangeY * 2);
			for (int j = 0; j < 255; j++)
			{
				if (Main.player[j].active && new Rectangle((int)Main.player[j].position.X, (int)Main.player[j].position.Y, Main.player[j].width, Main.player[j].height).Intersects(value))
				{
					flag = false;
					break;
				}
			}
			if (flag)
			{
				string text = Main.npc[num].name;
				if (Main.npc[num].displayName != "")
				{
					text = ((Lang.lang > 1) ? Main.npc[num].displayName : (Main.npc[num].displayName + " " + Lang.the + Main.npc[num].name));
				}
				if (Main.netMode == 0)
				{
					Main.NewText(text + " " + Lang.misc[35], 50, 125);
				}
				else if (Main.netMode == 2)
				{
					NetMessage.SendData(25, -1, -1, text + " " + Lang.misc[35], 255, 50f, 125f, 255f);
				}
				Main.npc[num].active = false;
				Main.npc[num].netSkip = -1;
				Main.npc[num].life = 0;
				NetMessage.SendData(23, -1, -1, "", num);
			}
		}

		public static void SpawnTravelNPC()
		{
			if (Main.eclipse || !Main.dayTime || (Main.invasionType > 0 && Main.invasionDelay == 0 && Main.invasionSize > 0))
			{
				return;
			}
			for (int i = 0; i < 200; i++)
			{
				if (Main.npc[i].active && Main.npc[i].type == 368)
				{
					return;
				}
			}
			Chest.SetupTravelShop();
			NetMessage.SendTravelShop();
			int num = 0;
			int[] array = new int[200];
			int num2 = 0;
			for (int j = 0; j < 200; j++)
			{
				if (Main.npc[j].active && Main.npc[j].townNPC && Main.npc[j].type != 37 && !Main.npc[j].homeless)
				{
					array[num2] = j;
					num2++;
				}
			}
			if (num2 == 0)
			{
				return;
			}
			num = array[Main.rand.Next(num2)];
			bestX = Main.npc[num].homeTileX;
			bestY = Main.npc[num].homeTileY;
			int minValue = bestX;
			int num3 = bestX;
			int num4 = bestY;
			int num5 = bestX;
			while (num5 > bestX - 10 && (SolidTile(num5, num4) || Main.tileSolidTop[Main.tile[num5, num4].type]) && (!Main.tile[num5, num4 - 1].active() || !Main.tileSolid[Main.tile[num5, num4 - 1].type] || Main.tileSolidTop[Main.tile[num5, num4 - 1].type]) && (!Main.tile[num5, num4 - 2].active() || !Main.tileSolid[Main.tile[num5, num4 - 2].type] || Main.tileSolidTop[Main.tile[num5, num4 - 2].type]) && (!Main.tile[num5, num4 - 3].active() || !Main.tileSolid[Main.tile[num5, num4 - 3].type] || Main.tileSolidTop[Main.tile[num5, num4 - 3].type]))
			{
				minValue = num5;
				num5--;
			}
			for (int k = bestX; k < bestX + 10 && (SolidTile(k, num4) || Main.tileSolidTop[Main.tile[k, num4].type]) && (!Main.tile[k, num4 - 1].active() || !Main.tileSolid[Main.tile[k, num4 - 1].type] || Main.tileSolidTop[Main.tile[k, num4 - 1].type]) && (!Main.tile[k, num4 - 2].active() || !Main.tileSolid[Main.tile[k, num4 - 2].type] || Main.tileSolidTop[Main.tile[k, num4 - 2].type]) && (!Main.tile[k, num4 - 3].active() || !Main.tileSolid[Main.tile[k, num4 - 3].type] || Main.tileSolidTop[Main.tile[k, num4 - 3].type]); k++)
			{
				num3 = k;
			}
			for (int l = 0; l < 30; l++)
			{
				int num6 = Main.rand.Next(minValue, num3 + 1);
				if (l < 20)
				{
					if (num6 < bestX - 1 || num6 > bestX + 1)
					{
						bestX = num6;
						break;
					}
				}
				else if (num6 != bestX)
				{
					bestX = num6;
					break;
				}
			}
			int num7 = bestX;
			int num8 = bestY;
			bool flag = false;
			if (!flag && !((double)num8 > Main.worldSurface))
			{
				for (int m = 20; m < 500; m++)
				{
					for (int n = 0; n < 2; n++)
					{
						num7 = ((n != 0) ? (bestX - m * 2) : (bestX + m * 2));
						if (num7 > 10 && num7 < Main.maxTilesX - 10)
						{
							int num9 = bestY - m;
							double num10 = bestY + m;
							if (num9 < 10)
							{
								num9 = 10;
							}
							if (num10 > Main.worldSurface)
							{
								num10 = Main.worldSurface;
							}
							for (int num11 = num9; (double)num11 < num10; num11++)
							{
								num8 = num11;
								if (!Main.tile[num7, num8].nactive() || !Main.tileSolid[Main.tile[num7, num8].type])
								{
									continue;
								}
								if (Main.tile[num7, num8 - 1].liquid != 0 || Collision.SolidTiles(num7 - 1, num7 + 1, num8 - 3, num8 - 1))
								{
									break;
								}
								flag = true;
								Rectangle value = new Rectangle(num7 * 16 + 8 - NPC.sWidth / 2 - NPC.safeRangeX, num8 * 16 + 8 - NPC.sHeight / 2 - NPC.safeRangeY, NPC.sWidth + NPC.safeRangeX * 2, NPC.sHeight + NPC.safeRangeY * 2);
								for (int num12 = 0; num12 < 255; num12++)
								{
									if (Main.player[num12].active && new Rectangle((int)Main.player[num12].position.X, (int)Main.player[num12].position.Y, Main.player[num12].width, Main.player[num12].height).Intersects(value))
									{
										flag = false;
										break;
									}
								}
								break;
							}
						}
						if (flag)
						{
							break;
						}
					}
					if (flag)
					{
						break;
					}
				}
			}
			int num13 = NPC.NewNPC(num7 * 16, num8 * 16, 368, 1);
			Main.npc[num13].homeTileX = bestX;
			Main.npc[num13].homeTileY = bestY;
			Main.npc[num13].homeless = true;
			if (num7 < bestX)
			{
				Main.npc[num13].direction = 1;
			}
			else if (num7 > bestX)
			{
				Main.npc[num13].direction = -1;
			}
			Main.npc[num13].netUpdate = true;
			string text = Main.npc[num13].name;
			if (Main.npc[num13].displayName != "")
			{
				text = ((Lang.lang > 1) ? Main.npc[num13].displayName : (Main.npc[num13].displayName + " " + Lang.the + Main.npc[num13].name));
			}
			if (Main.netMode == 0)
			{
				Main.NewText(text + " " + Lang.misc[18], 50, 125);
			}
			else if (Main.netMode == 2)
			{
				NetMessage.SendData(25, -1, -1, text + " " + Lang.misc[18], 255, 50f, 125f, 255f);
			}
		}

		public static void SpawnNPC(int x, int y)
		{
			if (Main.wallHouse[Main.tile[x, y].wall])
			{
				canSpawn = true;
			}
			if (!canSpawn || !StartRoomCheck(x, y) || !RoomNeeds(spawnNPC))
			{
				return;
			}
			ScoreRoom();
			if (hiScore <= 0)
			{
				return;
			}
			int num = -1;
			for (int i = 0; i < 200; i++)
			{
				if (Main.npc[i].active && Main.npc[i].homeless && Main.npc[i].type == spawnNPC && CheckConditions(Main.npc[i].type))
				{
					num = i;
					break;
				}
			}
			if (!NextNPC())
			{
				return;
			}
			if (num == -1)
			{
				int num2 = bestX;
				int num3 = bestY;
				bool flag = false;
				if (!flag)
				{
					flag = true;
					Rectangle value = new Rectangle(num2 * 16 + 8 - NPC.sWidth / 2 - NPC.safeRangeX, num3 * 16 + 8 - NPC.sHeight / 2 - NPC.safeRangeY, NPC.sWidth + NPC.safeRangeX * 2, NPC.sHeight + NPC.safeRangeY * 2);
					for (int j = 0; j < 255; j++)
					{
						if (Main.player[j].active && new Rectangle((int)Main.player[j].position.X, (int)Main.player[j].position.Y, Main.player[j].width, Main.player[j].height).Intersects(value))
						{
							flag = false;
							break;
						}
					}
				}
				if (!flag && !((double)num3 > Main.worldSurface))
				{
					for (int k = 1; k < 500; k++)
					{
						for (int l = 0; l < 2; l++)
						{
							num2 = ((l != 0) ? (bestX - k) : (bestX + k));
							if (num2 > 10 && num2 < Main.maxTilesX - 10)
							{
								int num4 = bestY - k;
								double num5 = bestY + k;
								if (num4 < 10)
								{
									num4 = 10;
								}
								if (num5 > Main.worldSurface)
								{
									num5 = Main.worldSurface;
								}
								for (int m = num4; (double)m < num5; m++)
								{
									num3 = m;
									if (!Main.tile[num2, num3].nactive() || !Main.tileSolid[Main.tile[num2, num3].type])
									{
										continue;
									}
									if (Collision.SolidTiles(num2 - 1, num2 + 1, num3 - 3, num3 - 1))
									{
										break;
									}
									flag = true;
									Rectangle value2 = new Rectangle(num2 * 16 + 8 - NPC.sWidth / 2 - NPC.safeRangeX, num3 * 16 + 8 - NPC.sHeight / 2 - NPC.safeRangeY, NPC.sWidth + NPC.safeRangeX * 2, NPC.sHeight + NPC.safeRangeY * 2);
									for (int n = 0; n < 255; n++)
									{
										if (Main.player[n].active && new Rectangle((int)Main.player[n].position.X, (int)Main.player[n].position.Y, Main.player[n].width, Main.player[n].height).Intersects(value2))
										{
											flag = false;
											break;
										}
									}
									break;
								}
							}
							if (flag)
							{
								break;
							}
						}
						if (flag)
						{
