			{
				Main.npc[npc].homeless = true;
			}
		}

		public static void ScoreRoom(int ignoreNPC = -1)
		{
			roomOccupied = false;
			roomEvil = false;
			for (int i = 0; i < 200; i++)
			{
				if (!Main.npc[i].active || !Main.npc[i].townNPC || ignoreNPC == i || Main.npc[i].homeless)
				{
					continue;
				}
				for (int j = 0; j < numRoomTiles; j++)
				{
					if (Main.npc[i].homeTileX != roomX[j] || Main.npc[i].homeTileY != roomY[j])
					{
						continue;
					}
					bool flag = false;
					for (int k = 0; k < numRoomTiles; k++)
					{
						if (Main.npc[i].homeTileX == roomX[k] && Main.npc[i].homeTileY - 1 == roomY[k])
						{
							flag = true;
							break;
						}
					}
					if (flag)
					{
						roomOccupied = true;
						hiScore = -1;
						return;
					}
				}
			}
			hiScore = 0;
			int num = 0;
			int num2 = 50;
			int num3 = 0;
			int num4 = roomX1 - Main.zoneX / 2 / 16 - 1 - Lighting.offScreenTiles;
			int num5 = roomX2 + Main.zoneX / 2 / 16 + 1 + Lighting.offScreenTiles;
			int num6 = roomY1 - Main.zoneY / 2 / 16 - 1 - Lighting.offScreenTiles;
			int num7 = roomY2 + Main.zoneY / 2 / 16 + 1 + Lighting.offScreenTiles;
			if (num4 < 0)
			{
				num4 = 0;
			}
			if (num5 >= Main.maxTilesX)
			{
				num5 = Main.maxTilesX - 1;
			}
			if (num6 < 0)
			{
				num6 = 0;
			}
			if (num7 > Main.maxTilesX)
			{
				num7 = Main.maxTilesX;
			}
			for (int l = num4 + 1; l < num5; l++)
			{
				for (int m = num6 + 2; m < num7 + 2; m++)
				{
					if (Main.tile[l, m].active())
					{
						if (Main.tile[l, m].type == 23 || Main.tile[l, m].type == 24 || Main.tile[l, m].type == 25 || Main.tile[l, m].type == 32 || Main.tile[l, m].type == 112 || Main.tile[l, m].type == 163)
						{
							num3++;
						}
						else if (Main.tile[l, m].type == 199 || Main.tile[l, m].type == 201 || Main.tile[l, m].type == 200 || Main.tile[l, m].type == 203 || Main.tile[l, m].type == 234)
						{
							num3++;
						}
						else if (Main.tile[l, m].type == 27)
						{
							num3 -= 5;
						}
						else if (Main.tile[l, m].type == 109 || Main.tile[l, m].type == 110 || Main.tile[l, m].type == 113 || Main.tile[l, m].type == 116 || Main.tile[l, m].type == 164)
						{
							num3--;
						}
					}
				}
			}
			if (num3 < 50)
			{
				num3 = 0;
			}
			num2 -= num3;
			if (num2 <= -250)
			{
				hiScore = num2;
				roomEvil = true;
				return;
			}
			num4 = roomX1;
			num5 = roomX2;
			num6 = roomY1;
			num7 = roomY2;
			for (int n = num4 + 1; n < num5; n++)
			{
				for (int num8 = num6 + 2; num8 < num7 + 2; num8++)
				{
					if (!Main.tile[n, num8].nactive())
					{
						continue;
					}
					num = num2;
					if (!Main.tileSolid[Main.tile[n, num8].type] || Main.tileSolidTop[Main.tile[n, num8].type] || Collision.SolidTiles(n - 1, n + 1, num8 - 3, num8 - 1) || !Main.tile[n - 1, num8].nactive() || !Main.tileSolid[Main.tile[n - 1, num8].type] || !Main.tile[n + 1, num8].nactive() || !Main.tileSolid[Main.tile[n + 1, num8].type])
					{
						continue;
					}
					for (int num9 = n - 2; num9 < n + 3; num9++)
					{
						for (int num10 = num8 - 4; num10 < num8; num10++)
						{
							if (Main.tile[num9, num10].nactive())
							{
								num = ((num9 != n) ? ((Main.tile[num9, num10].type != 10 && Main.tile[num9, num10].type != 11) ? ((!Main.tileSolid[Main.tile[num9, num10].type]) ? (num + 5) : (num - 5)) : (num - 20)) : (num - 15));
							}
						}
					}
					if (num <= hiScore)
					{
						continue;
					}
					bool flag2 = false;
					for (int num11 = 0; num11 < numRoomTiles; num11++)
					{
						if (roomX[num11] == n && roomY[num11] == num8)
						{
							flag2 = true;
							break;
						}
					}
					if (flag2)
					{
						hiScore = num;
						bestX = n;
						bestY = num8;
					}
				}
			}
		}

		public static bool StartRoomCheck(int x, int y)
		{
			roomX1 = x;
			roomX2 = x;
			roomY1 = y;
			roomY2 = y;
			numRoomTiles = 0;
			for (int i = 0; i < 340; i++)
			{
				houseTile[i] = false;
			}
			canSpawn = true;
			if (Main.tile[x, y].nactive() && Main.tileSolid[Main.tile[x, y].type])
			{
				canSpawn = false;
			}
			CheckRoom(x, y);
			if (numRoomTiles < 60)
			{
				canSpawn = false;
			}
			if (canSpawn)
			{
				return true;
			}
			return false;
		}

		public static void CheckRoom(int x, int y)
		{
			if (!canSpawn)
			{
				return;
			}
			if (x < 10 || y < 10 || x >= Main.maxTilesX - 10 || y >= lastMaxTilesY - 10)
			{
				canSpawn = false;
				return;
			}
			for (int i = 0; i < numRoomTiles; i++)
			{
				if (roomX[i] == x && roomY[i] == y)
				{
					return;
				}
			}
			roomX[numRoomTiles] = x;
			roomY[numRoomTiles] = y;
			numRoomTiles++;
			if (numRoomTiles >= maxRoomTiles)
			{
				canSpawn = false;
				return;
			}
			if (Main.tile[x, y].nactive())
			{
				houseTile[Main.tile[x, y].type] = true;
				if (Main.tileSolid[Main.tile[x, y].type] || (Main.tile[x, y].type == 11 && (Main.tile[x, y].frameX == 0 || Main.tile[x, y].frameX == 54)))
				{
					return;
				}
			}
			if (x < roomX1)
			{
				roomX1 = x;
			}
			if (x > roomX2)
			{
				roomX2 = x;
			}
			if (y < roomY1)
			{
				roomY1 = y;
			}
			if (y > roomY2)
			{
				roomY2 = y;
			}
			bool flag = false;
			bool flag2 = false;
			for (int j = -2; j < 3; j++)
			{
				if (Main.wallHouse[Main.tile[x + j, y].wall])
				{
					flag = true;
				}
				if (Main.tile[x + j, y].nactive() && (Main.tileSolid[Main.tile[x + j, y].type] || Main.tile[x + j, y].type == 11))
				{
					flag = true;
				}
				if (Main.wallHouse[Main.tile[x, y + j].wall])
				{
					flag2 = true;
				}
				if (Main.tile[x, y + j].nactive() && (Main.tileSolid[Main.tile[x, y + j].type] || Main.tile[x, y + j].type == 11))
				{
					flag2 = true;
				}
			}
			if (!flag || !flag2)
			{
				canSpawn = false;
				return;
			}
			for (int k = x - 1; k < x + 2; k++)
			{
				for (int l = y - 1; l < y + 2; l++)
				{
					if ((k != x || l != y) && canSpawn)
					{
						CheckRoom(k, l);
					}
				}
			}
		}

		public static void dropMeteor()
		{
			bool flag = true;
			int num = 0;
			if (Main.netMode == 1)
			{
				return;
			}
			for (int i = 0; i < 255; i++)
			{
				if (Main.player[i].active)
				{
					flag = false;
					break;
				}
			}
			int num2 = 0;
			float num3 = Main.maxTilesX / 4200;
			int num4 = (int)(400f * num3);
			for (int j = 5; j < Main.maxTilesX - 5; j++)
			{
				for (int k = 5; (double)k < Main.worldSurface; k++)
				{
					if (Main.tile[j, k].active() && Main.tile[j, k].type == 37)
					{
						num2++;
						if (num2 > num4)
						{
							return;
						}
					}
				}
			}
			while (!flag)
			{
				float num5 = (float)Main.maxTilesX * 0.08f;
				int num6 = Main.rand.Next(50, Main.maxTilesX - 50);
				while ((float)num6 > (float)Main.spawnTileX - num5 && (float)num6 < (float)Main.spawnTileX + num5)
				{
					num6 = Main.rand.Next(50, Main.maxTilesX - 50);
				}
				for (int l = Main.rand.Next(100); l < Main.maxTilesY; l++)
				{
					if (Main.tile[num6, l].active() && Main.tileSolid[Main.tile[num6, l].type])
					{
						flag = meteor(num6, l);
						break;
					}
				}
				num++;
				if (num >= 100)
				{
					break;
				}
			}
		}

		public static bool meteor(int i, int j)
		{
			if (i < 50 || i > Main.maxTilesX - 50)
			{
				return false;
			}
			if (j < 50 || j > Main.maxTilesY - 50)
			{
				return false;
			}
			int num = 25;
			Rectangle rectangle = new Rectangle((i - num) * 16, (j - num) * 16, num * 2 * 16, num * 2 * 16);
			for (int k = 0; k < 255; k++)
			{
				if (Main.player[k].active)
				{
					Rectangle value = new Rectangle((int)(Main.player[k].position.X + (float)(Main.player[k].width / 2) - (float)(NPC.sWidth / 2) - (float)NPC.safeRangeX), (int)(Main.player[k].position.Y + (float)(Main.player[k].height / 2) - (float)(NPC.sHeight / 2) - (float)NPC.safeRangeY), NPC.sWidth + NPC.safeRangeX * 2, NPC.sHeight + NPC.safeRangeY * 2);
					if (rectangle.Intersects(value))
					{
						return false;
					}
				}
			}
			for (int l = 0; l < 200; l++)
			{
				if (Main.npc[l].active)
				{
					Rectangle value2 = new Rectangle((int)Main.npc[l].position.X, (int)Main.npc[l].position.Y, Main.npc[l].width, Main.npc[l].height);
					if (rectangle.Intersects(value2))
					{
						return false;
					}
				}
			}
			for (int m = i - num; m < i + num; m++)
			{
				for (int n = j - num; n < j + num; n++)
				{
					if (Main.tile[m, n].active() && Main.tile[m, n].type == 21)
					{
						return false;
					}
				}
			}
			stopDrops = true;
			num = 15;
			for (int num2 = i - num; num2 < i + num; num2++)
			{
				for (int num3 = j - num; num3 < j + num; num3++)
				{
					if (num3 > j + Main.rand.Next(-2, 3) - 5 && (double)(Math.Abs(i - num2) + Math.Abs(j - num3)) < (double)num * 1.5 + (double)Main.rand.Next(-5, 5))
					{
						if (!Main.tileSolid[Main.tile[num2, num3].type])
						{
							Main.tile[num2, num3].active(false);
						}
						Main.tile[num2, num3].type = 37;
					}
				}
			}
			num = 10;
			for (int num4 = i - num; num4 < i + num; num4++)
			{
				for (int num5 = j - num; num5 < j + num; num5++)
				{
					if (num5 > j + Main.rand.Next(-2, 3) - 5 && Math.Abs(i - num4) + Math.Abs(j - num5) < num + Main.rand.Next(-3, 4))
					{
						Main.tile[num4, num5].active(false);
					}
				}
			}
			num = 16;
			for (int num6 = i - num; num6 < i + num; num6++)
			{
				for (int num7 = j - num; num7 < j + num; num7++)
				{
					if (Main.tile[num6, num7].type == 5 || Main.tile[num6, num7].type == 32)
					{
						KillTile(num6, num7);
					}
					SquareTileFrame(num6, num7);
					SquareWallFrame(num6, num7);
				}
			}
			num = 23;
			for (int num8 = i - num; num8 < i + num; num8++)
			{
				for (int num9 = j - num; num9 < j + num; num9++)
				{
					if (Main.tile[num8, num9].active() && Main.rand.Next(10) == 0 && (double)(Math.Abs(i - num8) + Math.Abs(j - num9)) < (double)num * 1.3)
					{
						if (Main.tile[num8, num9].type == 5 || Main.tile[num8, num9].type == 32)
						{
							KillTile(num8, num9);
						}
						Main.tile[num8, num9].type = 37;
						SquareTileFrame(num8, num9);
					}
				}
			}
			stopDrops = false;
			if (Main.netMode == 0)
			{
				Main.NewText(Lang.gen[59], 50, byte.MaxValue, 130);
			}
			else if (Main.netMode == 2)
			{
				NetMessage.SendData(25, -1, -1, Lang.gen[59], 255, 50f, 255f, 130f);
			}
			if (Main.netMode != 1)
			{
				NetMessage.SendTileSquare(-1, i, j, 30);
			}
			return true;
		}

