		public static void worldGenCallBack(object threadContext)
		{
			Main.PlaySound(10);
			clearWorld();
			generateWorld();
			WorldFile.saveWorld(true);
			Main.LoadWorlds();
			if (Main.menuMode == 10)
			{
				Main.menuMode = 6;
			}
			Main.PlaySound(10);
		}

		public static void CreateNewWorld()
		{
			ThreadPool.QueueUserWorkItem(worldGenCallBack, 1);
		}

		public static void SaveAndQuitCallBack(object threadContext)
		{
			try
			{
				Main.PlaySound(34, -1, -1, 0);
				Main.PlaySound(35, -1, -1, 0);
			}
			catch
			{
			}
			Main.menuMode = 10;
			Main.gameMenu = true;
			Player.SavePlayer(Main.player[Main.myPlayer], Main.playerPathName);
			if (Main.netMode == 0)
			{
				WorldFile.saveWorld();
				Main.PlaySound(10);
			}
			else
			{
				Netplay.disconnect = true;
				Main.netMode = 0;
			}
			Main.menuMode = 0;
		}

		public static void SaveAndQuit()
		{
			Main.PlaySound(11);
			ThreadPool.QueueUserWorkItem(SaveAndQuitCallBack, 1);
		}

		public static void playWorldCallBack(object threadContext)
		{
			if (Main.rand == null)
			{
				Main.rand = new Random((int)DateTime.Now.Ticks);
			}
			for (int i = 0; i < 255; i++)
			{
				if (i != Main.myPlayer)
				{
					Main.player[i].active = false;
				}
			}
			noMapUpdate = true;
			WorldFile.loadWorld();
			if (loadFailed || !loadSuccess)
			{
				WorldFile.loadWorld();
				if (loadFailed || !loadSuccess)
				{
					if (File.Exists(Main.worldPathName + ".bak"))
					{
						worldBackup = true;
					}
					else
					{
						worldBackup = false;
					}
					if (!Main.dedServ)
					{
						if (worldBackup)
						{
							Main.menuMode = 200;
						}
						else
						{
							Main.menuMode = 201;
						}
						return;
					}
					if (!worldBackup)
					{
						Console.WriteLine("Load failed!  No backup found.");
						return;
					}
					File.Copy(Main.worldPathName, Main.worldPathName + ".bad", true);
					File.Copy(Main.worldPathName + ".bak", Main.worldPathName, true);
					File.Delete(Main.worldPathName + ".bak");
					WorldFile.loadWorld();
					if (loadFailed || !loadSuccess)
					{
						WorldFile.loadWorld();
						if (loadFailed || !loadSuccess)
						{
							File.Copy(Main.worldPathName, Main.worldPathName + ".bak", true);
							File.Copy(Main.worldPathName + ".bad", Main.worldPathName, true);
							File.Delete(Main.worldPathName + ".bad");
							Console.WriteLine("Load failed!");
							return;
						}
					}
				}
			}
			if (Main.mapEnabled)
			{
				Map.loadMap();
			}
			if (Main.netMode != 2)
			{
				Main.sectionManager.SetAllFramesLoaded();
			}
			while (Main.loadMapLock)
			{
				float num = (float)Main.loadMapLastX / (float)Main.maxTilesX;
				Main.statusText = Lang.gen[68] + " " + (int)(num * 100f + 1f) + "%";
				Thread.Sleep(0);
				if (!Main.mapEnabled)
				{
					break;
				}
			}
			if (Main.gameMenu)
			{
				Main.gameMenu = false;
			}
