		public static int countTiles(int x, int y, bool jungle = false, bool lavaOk = false)
		{
			numTileCount = 0;
			lavaCount = 0;
			iceCount = 0;
			rockCount = 0;
			nextCount(x, y, jungle, lavaOk);
			return numTileCount;
		}

		public static void nextCount(int x, int y, bool jungle = false, bool lavaOk = false)
		{
			if (numTileCount >= maxTileCount)
			{
				return;
			}
			if (x <= 1 || x >= Main.maxTilesX - 1 || y <= 1 || y >= Main.maxTilesY - 1)
			{
				numTileCount = maxTileCount;
				return;
			}
			for (int i = 0; i < numTileCount; i++)
			{
				if (countX[i] == x && countY[i] == y)
				{
					return;
				}
			}
			if (!jungle)
			{
				if (Main.tile[x, y].wall != 0)
				{
					numTileCount = maxTileCount;
					return;
				}
				if (!lavaOk)
				{
					if (Main.tile[x, y].lava() && Main.tile[x, y].liquid > 0)
					{
						lavaCount++;
						numTileCount = maxTileCount;
						return;
					}
				}
				else if (Main.tile[x, y].lava() && Main.tile[x, y].liquid > 0)
				{
					lavaCount++;
				}
			}
			if (Main.tile[x, y].active())
			{
				if (Main.tile[x, y].type == 1)
				{
					rockCount++;
				}
				if (Main.tile[x, y].type == 147 || Main.tile[x, y].type == 161)
				{
					iceCount++;
				}
			}
			if (!SolidTile(x, y))
			{
				countX[numTileCount] = x;
				countY[numTileCount] = y;
				numTileCount++;
				nextCount(x - 1, y, jungle, lavaOk);
				nextCount(x + 1, y, jungle, lavaOk);
				nextCount(x, y - 1, jungle, lavaOk);
				nextCount(x, y + 1, jungle, lavaOk);
			}
		}

		public static int countDirtTiles(int x, int y)
		{
			numTileCount = 0;
			nextDirtCount(x, y);
			return numTileCount;
		}

		public static void nextDirtCount(int x, int y)
		{
			if (numTileCount >= maxTileCount)
			{
				return;
			}
			if (x <= 1 || x >= Main.maxTilesX - 1 || y <= 1 || y >= Main.maxTilesY - 1)
			{
				numTileCount = maxTileCount;
				return;
			}
			for (int i = 0; i < numTileCount; i++)
			{
				if (countX[i] == x && countY[i] == y)
				{
					return;
				}
			}
			if (Main.tile[x, y].active() && (Main.tile[x, y].type == 147 || Main.tile[x, y].type == 161))
			{
				numTileCount = maxTileCount;
			}
			else if (Main.tile[x, y].wall == 78 || Main.tile[x, y].wall == 83 || Main.tile[x, y].wall == 3)
			{
				numTileCount = maxTileCount;
			}
			else if (!SolidTile(x, y) && (Main.tile[x, y].wall == 2 || Main.tile[x, y].wall == 59))
			{
				countX[numTileCount] = x;
				countY[numTileCount] = y;
				numTileCount++;
				nextDirtCount(x - 1, y);
				nextDirtCount(x + 1, y);
				nextDirtCount(x, y - 1);
				nextDirtCount(x, y + 1);
				nextDirtCount(x - 1, y - 1);
				nextDirtCount(x - 1, y + 1);
				nextDirtCount(x + 1, y - 1);
				nextDirtCount(x + 1, y + 1);
				nextDirtCount(x - 2, y);
				nextDirtCount(x + 2, y);
			}
		}

		public static void mossCave(int x, int y)
		{
			mossOut(x, y);
		}

		public static void mossOut(int x, int y)
		{
			if (!SolidTile(x, y) && Main.tile[x, y].wall == 0)
			{
				Main.tile[x, y].wall = mossWall;
				mossOut(x - 1, y);
				mossOut(x + 1, y);
				mossOut(x, y - 1);
				mossOut(x, y + 1);
			}
			else if (Main.tile[x, y].active())
			{
				if (Main.tile[x, y].wall == 0)
				{
					Main.tile[x, y].wall = mossWall;
				}
				int type = Main.tile[x, y].type;
				if (type == 1)
				{
					Main.tile[x, y].type = mossTile;
				}
			}
		}

		public static void wallOut(int x, int y, int wall)
		{
			if (!SolidTile(x, y) && Main.tile[x, y].wall == 0)
			{
				Main.tile[x, y].wall = (byte)wall;
				wallOut(x - 1, y, wall);
				wallOut(x + 1, y, wall);
				wallOut(x, y - 1, wall);
				wallOut(x, y + 1, wall);
			}
			else if (Main.tile[x, y].active() && Main.tile[x, y].wall == 0)
			{
				Main.tile[x, y].wall = (byte)wall;
			}
		}

		public static void wallOut2(int x, int y, int wall)
		{
			try
			{
				if (!SolidTile(x, y) && Main.tile[x, y].wall != wall && Main.tile[x, y].wall != 4 && Main.tile[x, y].wall != 40 && Main.tile[x, y].wall != 3)
