		public static void gemOut(int x, int y)
		{
			if (!SolidTile(x, y) && Main.tile[x, y].wall == 0)
			{
				Main.tile[x, y].wall = (byte)(48 + randGem());
				if (!Main.tile[x, y].active() && genRand.Next(2) == 0)
				{
					PlaceTile(x, y, 178, true, false, -1, randGem());
				}
				gemOut(x - 1, y);
				gemOut(x + 1, y);
				gemOut(x, y - 1);
				gemOut(x, y + 1);
			}
			else
			{
				if (!Main.tile[x, y].active())
				{
					return;
				}
				int type = Main.tile[x, y].type;
				if (type == 0 || type == 1 || type == 40 || type == 59 || type == 60 || type == 70 || type == 147 || type == 161)
				{
					Main.tile[x, y].type = randGemTile();
				}
				for (int i = 0; i < 4; i++)
				{
					int num = x;
					int num2 = y;
					if (i == 0)
					{
						x--;
					}
					if (i == 1)
					{
						x++;
					}
					if (i == 2)
					{
						y--;
					}
					if (i == 3)
					{
						y++;
					}
					type = Main.tile[num, num2].type;
					if (type == 0 || type == 1 || type == 40 || type == 59 || type == 60 || type == 70 || type == 147 || type == 161)
					{
						Main.tile[num, num2].type = randGemTile();
					}
				}
			}
		}

		public static void spiderOut(int x, int y)
