									PlaceSmallPile(x, y, 48 + genRand.Next(6), 0, 185);
								}
							}
						}
					}
				}
				spiderOut(x - 1, y);
				spiderOut(x + 1, y);
				spiderOut(x, y - 1);
				spiderOut(x, y + 1);
			}
			else if (Main.tile[x, y].active() && Main.tile[x, y].wall == 0)
			{
