		public static void dWallOut(int x, int y, int wall)
		{
			if (!SolidTile(x, y) && Main.tile[x, y].wall != wall && Main.tile[x, y].wall > 0)
			{
				dWallCount++;
				if (dWallCount > 1000)
				{
					Main.tile[x, y].wall = 17;
					dWallBroke = true;
					return;
				}
				Main.tile[x, y].wall = (byte)wall;
				if (Main.tile[x - 1, y].wall != wall)
				{
					dWallOut(x - 1, y, wall);
				}
				if (Main.tile[x + 1, y].wall != wall)
				{
					dWallOut(x + 1, y, wall);
				}
				if (Main.tile[x, y - 1].wall != wall)
				{
					dWallOut(x, y - 1, wall);
				}
				if (Main.tile[x, y + 1].wall != wall)
				{
					dWallOut(x, y + 1, wall);
				}
			}
			else if (Main.tile[x, y].active())
			{
				Main.tile[x, y].wall = (byte)wall;
			}
		}

		public static bool nearPicture(int x, int y)
		{
			for (int i = x - 4; i <= x + 3; i++)
