					{
						if (num == num2)
						{
							num3 += num7;
							continue;
						}
						tileCounts[num2] += num3;
						num2 = num;
						num3 = num7;
					}
				}
				tileCounts[num2] += num3;
				num3 = 0;
				num4++;
			}
			while (num4 < 2);
